import modal

app = modal.App("text-pipeline")

# Define the Modal image
image = modal.Image.debian_slim()


@app.function(image=image)
def clean_text(text: str) -> str:
    """Strips leading/trailing whitespace and converts to lowercase."""
    return text.strip().lower()


@app.function(image=image)
def count_words(text: str) -> int:
    """Counts the number of words in the text."""
    return len(text.split())


@app.function(image=image)
def summarize(original_text: str, word_count: int) -> dict:
    """Returns a summary dictionary with text statistics."""
    cleaned_text = original_text.strip().lower()
    return {
        "original_length": len(original_text),
        "word_count": word_count,
        "cleaned_length": len(cleaned_text)
    }


@app.local_entrypoint()
def main():
    """Local entrypoint that runs the text processing pipeline."""
    # Sample text
    sample_text = "  Hello World this is a TEST of the pipeline  "

    # Run the pipeline
    cleaned = clean_text.remote(sample_text)
    word_count = count_words.remote(cleaned)
    summary = summarize.remote(sample_text, word_count)

    # Store results in a Modal Dict
    modal.Dict.put(
        "text-pipeline-output",
        {
            "summary": summary,
            "pipeline_stages": 3
        }
    )

    # Print results for visibility
    print("Pipeline Results:")
    print(f"  Original: '{sample_text}'")
    print(f"  Cleaned: '{cleaned}'")
    print(f"  Word Count: {word_count}")
    print(f"  Summary: {summary}")

